from board import Board, Piece
from player import Player
import random

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("white"), Player("black")]
        self.current_turn = 0

    def initialize(self):
        self.board.initialize()

    def get_valid_moves(self, player_color):
        valid_moves = []
        for piece in self.board.get_pieces(player_color):
            moves = piece.get_moves(self.board)
            if moves:
                valid_moves.extend(moves)
        return valid_moves

    def make_move(self, from_pos, to_pos):
        piece = self.board.get_piece(from_pos[0], from_pos[1])
        if piece and piece.color == "white" and self.current_turn % 2 == 0 or piece.color == "black" and self.current_turn % 2 == 1:
            capture = piece.move(self.board, to_pos)
            if capture:
                self.remove_captured_piece(capture)
                self.check_king(piece)
            self.current_turn += 1
            return True
        return False

    def check_winner(self):
        valid_moves = self.get_valid_moves("white") if self.current_turn % 2 == 0 else self.get_valid_moves("black")
        return len(valid_moves) == 0

    def remove_captured_piece(self, position):
        self.board.set_piece(position[0], position[1], None)

    def check_king(self, piece):
        if piece.is_at_edge():
            piece.king()

    @property
    def current_player(self):
        return self.players[self.current_turn % 2]

    @current_player.setter
    def current_player(self, value):
        self.current_turn = (self.current_turn + 1) if value == "black" else self.current_turn

