class Piece:
    def __init__(self, color, kinged=False):
        self.color = color
        self.kinged = kinged

    def get_moves(self, board):
        moves = []
        if not self.is_king():
            moves.extend(self.get_diagonal_moves(board))
        else:
            moves.extend(self.get_all_moves(board))
        return moves

    def get_diagonal_moves(self, board):
        moves = []
        directions = [(1, 1), (1, -1), (-1, 1), (-1, -1)]
        for dx, dy in directions:
            if self.color == "white":
                move_direction = dx * 1
            else:
                move_direction = dx * -1

            x, y = self.position
            while board.is_valid_position(x + dx, y + dy):
                if board.get_piece(x + dx, y + dy) is None:
                    moves.append(((x, y), (x + dx, y + dy)))
                    break
                elif board.get_piece(x + dx, y + dy).color != self.color and board.is_valid_position(x + move_direction * 2, y + move_direction * 2):
                    if board.get_piece(x + move_direction * 2, y + move_direction * 2) is None:
                        moves.append(((x, y), (x + move_direction * 2, y + move_direction * 2)))
                        break
                break

        return moves

    def get_all_moves(self, board):
        moves = []
        directions = [(1, 1), (1, -1), (-1, 1), (-1, -1)]
        for dx, dy in directions:
            x, y = self.position
            while board.is_valid_position(x + dx, y + dy):
                if board.get_piece(x + dx, y + dy) is None:
                    moves.append(((x, y), (x + dx, y + dy)))
                elif board.get_piece(x + dx, y + dy).color != self.color:
                    break
                else:
                    break
        return moves

    def move(self, board, to_pos):
        from_x, from_y = self.position
        to_x, to_y = to_pos
        if board.is_valid_position(to_x, to_y) and abs(from_x - to_x) == 1 and abs(from_y - to_y) == 1:
            piece = board.get_piece(to_x, to_y)
            if piece is None or piece.color != self.color:
                board.set_piece(from_x, from_y, None)
                board.set_piece(to_x, to_y, self)
                self.position = (to_x, to_y)
                return piece
        return None

    def king(self):
        self.kinged = True

    def is_king(self):
        return self.kinged

    @property
    def position(self):
        for row in range(8):
            for col in range(8):
                if self == board.grid[row][col]:
                    return (row, col)
